package server
import "net/http"
func (s *Server) dashboard(w http.ResponseWriter, r *http.Request) { w.Header().Set("Content-Type", "text/html"); w.Write([]byte(dashHTML)) }
const dashHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Courier</title>
<link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet">
<style>:root{--bg:#1a1410;--bg2:#241e18;--bg3:#2e261e;--rust:#e8753a;--leather:#a0845c;--cream:#f0e6d3;--cd:#bfb5a3;--cm:#7a7060;--gold:#d4a843;--green:#4a9e5c;--red:#c94444;--blue:#5b8dd9;--mono:'JetBrains Mono',monospace}*{margin:0;padding:0;box-sizing:border-box}body{background:var(--bg);color:var(--cream);font-family:var(--mono);line-height:1.5}.hdr{padding:1rem 1.5rem;border-bottom:1px solid var(--bg3);display:flex;justify-content:space-between;align-items:center}.hdr h1{font-size:.9rem;letter-spacing:2px}.hdr h1 span{color:var(--rust)}.main{padding:1.5rem;max-width:960px;margin:0 auto}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:.5rem;margin-bottom:1rem}.st{background:var(--bg2);border:1px solid var(--bg3);padding:.6rem;text-align:center}.st-v{font-size:1.2rem;font-weight:700}.st-l{font-size:.5rem;color:var(--cm);text-transform:uppercase;letter-spacing:1px;margin-top:.15rem}.toolbar{display:flex;gap:.5rem;margin-bottom:1rem;align-items:center}.search{flex:1;padding:.4rem .6rem;background:var(--bg2);border:1px solid var(--bg3);color:var(--cream);font-family:var(--mono);font-size:.7rem}.search:focus{outline:none;border-color:var(--leather)}.item{background:var(--bg2);border:1px solid var(--bg3);padding:.6rem .8rem;margin-bottom:.4rem;transition:border-color .2s;font-size:.7rem}.item:hover{border-color:var(--leather)}.item-top{display:flex;justify-content:space-between;align-items:center;gap:.5rem}.item-meta{font-size:.55rem;color:var(--cm);margin-top:.2rem;display:flex;gap:.5rem;flex-wrap:wrap;align-items:center}.badge{font-size:.5rem;padding:.12rem .35rem;text-transform:uppercase;letter-spacing:1px;border:1px solid}.badge.pending{border-color:var(--gold);color:var(--gold)}.badge.processing{border-color:var(--blue);color:var(--blue)}.badge.delivered{border-color:var(--green);color:var(--green)}.badge.failed{border-color:var(--red);color:var(--red)}.payload{font-size:.55rem;color:var(--cm);background:var(--bg);padding:.2rem .4rem;border:1px solid var(--bg3);margin-top:.2rem;word-break:break-all;max-height:40px;overflow:hidden}.btn{font-size:.6rem;padding:.25rem .5rem;cursor:pointer;border:1px solid var(--bg3);background:var(--bg);color:var(--cd);transition:all .2s}.btn:hover{border-color:var(--leather);color:var(--cream)}.btn-p{background:var(--rust);border-color:var(--rust);color:#fff}.btn-sm{font-size:.55rem;padding:.2rem .4rem}.modal-bg{display:none;position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:100;align-items:center;justify-content:center}.modal-bg.open{display:flex}.modal{background:var(--bg2);border:1px solid var(--bg3);padding:1.5rem;width:460px;max-width:92vw}.modal h2{font-size:.8rem;margin-bottom:1rem;color:var(--rust);letter-spacing:1px}.fr{margin-bottom:.6rem}.fr label{display:block;font-size:.55rem;color:var(--cm);text-transform:uppercase;letter-spacing:1px;margin-bottom:.2rem}.fr input,.fr select,.fr textarea{width:100%;padding:.4rem .5rem;background:var(--bg);border:1px solid var(--bg3);color:var(--cream);font-family:var(--mono);font-size:.7rem}.fr input:focus,.fr textarea:focus{outline:none;border-color:var(--leather)}.row2{display:grid;grid-template-columns:1fr 1fr;gap:.5rem}.acts{display:flex;gap:.4rem;justify-content:flex-end;margin-top:1rem}.empty{text-align:center;padding:3rem;color:var(--cm);font-style:italic;font-size:.75rem}</style></head><body>
<div class="hdr"><h1><span>&#9670;</span> COURIER</h1><button class="btn btn-p" onclick="openForm()">+ Enqueue</button></div>
<div class="main"><div class="stats" id="stats"></div><div class="toolbar"><input class="search" id="search" placeholder="Search messages..." oninput="render()"></div><div id="list"></div></div>
<div class="modal-bg" id="mbg" onclick="if(event.target===this)closeModal()"><div class="modal" id="mdl"></div></div>
<script>
var A='/api',items=[],editId=null;
async function load(){var r=await fetch(A+'/messages').then(function(r){return r.json()});items=r.messages||[];renderStats();render();}
function renderStats(){var total=items.length;var pending=items.filter(function(m){return m.status==='pending'}).length;var delivered=items.filter(function(m){return m.status==='delivered'}).length;var failed=items.filter(function(m){return m.status==='failed'}).length;
document.getElementById('stats').innerHTML='<div class="st"><div class="st-v">'+total+'</div><div class="st-l">Total</div></div><div class="st"><div class="st-v" style="color:var(--gold)">'+pending+'</div><div class="st-l">Pending</div></div><div class="st"><div class="st-v" style="color:var(--green)">'+delivered+'</div><div class="st-l">Delivered</div></div><div class="st"><div class="st-v" style="color:var(--red)">'+failed+'</div><div class="st-l">Failed</div></div>';}
function render(){var q=(document.getElementById('search').value||'').toLowerCase();var f=items;
if(q)f=f.filter(function(m){return(m.queue||'').toLowerCase().includes(q)||(m.payload||'').toLowerCase().includes(q)});
if(!f.length){document.getElementById('list').innerHTML='<div class="empty">No messages in queue.</div>';return;}
var h='';f.forEach(function(m){
h+='<div class="item"><div class="item-top"><div style="display:flex;gap:.4rem;align-items:center"><span class="badge '+m.status+'">'+m.status+'</span><span style="font-weight:700">'+esc(m.queue||'default')+'</span></div>';
h+='<div style="display:flex;gap:.3rem">';
if(m.status==='failed')h+='<button class="btn btn-sm" onclick="retry(''+m.id+'')">Retry</button>';
h+='<button class="btn btn-sm" onclick="del(''+m.id+'')" style="color:var(--red)">&#10005;</button></div></div>';
if(m.payload)h+='<div class="payload">'+esc(m.payload)+'</div>';
h+='<div class="item-meta"><span>Priority: '+m.priority+'</span><span>Retries: '+m.retries+'/'+m.max_retries+'</span>';
if(m.processed_at)h+='<span>Processed: '+ft(m.processed_at)+'</span>';
h+='<span>'+ft(m.created_at)+'</span></div></div>';});
document.getElementById('list').innerHTML=h;}
async function retry(id){await fetch(A+'/messages/'+id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:'pending'})});load();}
async function del(id){if(!confirm('Delete?'))return;await fetch(A+'/messages/'+id,{method:'DELETE'});load();}
function openForm(){document.getElementById('mdl').innerHTML='<h2>ENQUEUE MESSAGE</h2><div class="fr"><label>Queue *</label><input id="f-queue" placeholder="default"></div><div class="fr"><label>Payload</label><textarea id="f-payload" rows="4" placeholder='{"action":"send_email"}'></textarea></div><div class="row2"><div class="fr"><label>Priority</label><input id="f-pri" type="number" value="0"></div><div class="fr"><label>Max Retries</label><input id="f-retry" type="number" value="3"></div></div><div class="acts"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-p" onclick="submit()">Enqueue</button></div>';document.getElementById('mbg').classList.add('open');}
function closeModal(){document.getElementById('mbg').classList.remove('open');}
async function submit(){var queue=document.getElementById('f-queue').value.trim()||'default';
await fetch(A+'/messages',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({queue:queue,payload:document.getElementById('f-payload').value.trim(),priority:parseInt(document.getElementById('f-pri').value)||0,max_retries:parseInt(document.getElementById('f-retry').value)||3})});closeModal();load();}
function ft(t){if(!t)return'';try{return new Date(t).toLocaleDateString('en-US',{month:'short',day:'numeric'})}catch(e){return t;}}
function esc(s){if(!s)return'';var d=document.createElement('div');d.textContent=s;return d.innerHTML;}
document.addEventListener('keydown',function(e){if(e.key==='Escape')closeModal();});load();
</script></body></html>`
